const body = $json.body ?? $json;
const items = Array.isArray(body.items) ? body.items : [];
const missing = [];
for (const field of ['storeId', 'customerName', 'items']) {
  if (!body[field] || (field === 'items' && !items.length)) missing.push(field);
}
const normalizedItems = items.map((item) => ({
  sku: item.sku ?? item.id ?? 'unknown',
  name: item.name ?? item.title ?? 'Unnamed item',
  quantity: Number(item.quantity ?? item.qty ?? 1),
  modifiers: item.modifiers ?? [],
  notes: item.notes ?? ''
}));
return [{
  json: {
    workflow: 'qsr-order-intake-normalizer',
    status: missing.length ? 'needs_review' : 'ready_for_pos',
    missing,
    order: {
      storeId: body.storeId ?? 'unknown',
      channel: body.channel ?? 'webhook',
      customerName: body.customerName ?? body.name ?? 'Guest',
      customerPhone: body.customerPhone ?? body.phone ?? null,
      requestedTime: body.requestedTime ?? 'asap',
      items: normalizedItems,
      orderNotes: body.notes ?? ''
    },
    nextStep: missing.length ? 'route_to_manager_review' : 'send_to_pos_or_kitchen_display'
  }
}];
